const cam = await Camera.open()

const shader = new GLShader(`
  vec4 c = texture2D(uVideo, uv);
  float energy = uCustom.x;
  float shift  = uCustom.y;

  vec3 col = c.rgb;
  col.r *= 1.0 + energy * 3.0;
  col = mix(col, col.grb, shift);
  gl_FragColor = vec4(col, 1.0);
`)

pipe(cam).glshader(shader).show('Reactive Cam')

