const cam = await Camera.open()

const shader = new GLShader(`
  vec4 c     = texture2D(uVideo, uv);
  float bass   = uCustom.x;
  float mouseX = uCustom.y;

  vec3 tint = mix(
    vec3(0.1, 0.4, 1.0),
    vec3(1.0, 0.3, 0.05),
    mouseX
  );
  gl_FragColor = vec4(c.rgb * tint * (1.0 + bass * 2.0), 1.0);
`)

const mouse = sensors.mouse()


// ── WIRE IT TOGETHER ─────────────────────────────
pipe(cam).glshader(shader).show('My Sketch')

